package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Constructor;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVPrinter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormat_singleValue() throws IOException {
        String result = csvFormat.format("value");
        assertEquals("value", result);
    }

    @Test
    void testFormat_multipleValues() throws IOException {
        String result = csvFormat.format("value1", "value2", "value3");
        assertEquals("value1,value2,value3", result);
    }

    @Test
    void testFormat_nullValue() throws IOException {
        String result = csvFormat.format((Object) null);
        assertEquals("", result);
    }

    @Test
    void testFormat_emptyValues() throws IOException {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormat_withIOException() throws Exception {
        // Use reflection to replace CSVPrinter constructor temporarily
        Constructor<CSVPrinter> realConstructor = CSVPrinter.class.getDeclaredConstructor(Appendable.class, CSVFormat.class);
        realConstructor.setAccessible(true);

        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        doThrow(new IOException("IO error")).when(mockPrinter).printRecord((Object[]) any());

        CSVFormat csvFormatSpy = spy(csvFormat);

        // Use a spy on CSVFormat to override format method to inject mockPrinter
        // Because we cannot mock constructor easily, we override format method here
        CSVFormat csvFormatWithMock = new CSVFormat(csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                null,
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter(),
                csvFormat.getAutoFlush()) {
            @Override
            public String format(final Object... values) {
                final StringWriter out = new StringWriter();
                try (final CSVPrinter ignored = mockPrinter) {
                    mockPrinter.printRecord(values);
                    return out.toString().trim();
                } catch (final IOException e) {
                    throw new IllegalStateException(e);
                }
            }
        };

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            csvFormatWithMock.format("value");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }
}
